/**
 * AI service with shared RTDB-backed response cache.
 *
 * When `runPrompt` is called with a `cacheKey` + `ttlMs`, the result is
 * persisted to RTDB at `aiCache/{sanitizedKey}` so every visitor sees the
 * same answer until the TTL elapses. The first user past expiry regenerates.
 *
 * Schema for `aiCache/{sanitizedKey}`:
 *   { value: string, prompt?: string, generatedAt: number (server ts),
 *     ttlMs: number, lock?: boolean, lockedAt?: number }
 *
 * TTL is checked at READ time only — there is no auto-eviction.
 *
 * Example:
 *   const text = await runPrompt('summarize today vibe',
 *     { cacheKey: 'home_vibe', ttlMs: 1800000 });
 */

import { app, database } from './firebase';
import { ref, get, set, remove, serverTimestamp } from 'firebase/database';
import { BUILD_SHA } from './buildInfo';

const DEFAULT_MODEL = 'gemini-2.5-flash';
const LOCK_TTL_MS = 30000;
const POLL_INTERVAL_MS = 1000;
const POLL_MAX_MS = 5000;

let _modelCache = new Map();
let _aiInstance = null;

async function _getModel(modelName) {
  const { getAI, getGenerativeModel, GoogleAIBackend } = await import('firebase/ai');
  if (!_aiInstance) {
    _aiInstance = getAI(app, { backend: new GoogleAIBackend() });
  }
  if (!_modelCache.has(modelName)) {
    _modelCache.set(modelName, getGenerativeModel(_aiInstance, { model: modelName }));
  }
  return _modelCache.get(modelName);
}

function _composePrompt(prompt, data) {
  if (data === undefined || data === null) return prompt;
  const payload = typeof data === 'string' ? data : JSON.stringify(data, null, 2);
  return `${prompt}\n\n${payload}`;
}

function _buildRequest(prompt, options = {}) {
  const { data, system, maxTokens, temperature } = options;
  const userText = _composePrompt(prompt, data);
  const req = {
    contents: [{ role: 'user', parts: [{ text: userText }] }],
  };
  if (system) {
    req.systemInstruction = { role: 'system', parts: [{ text: system }] };
  }
  const generationConfig = {};
  if (typeof maxTokens === 'number') generationConfig.maxOutputTokens = maxTokens;
  if (typeof temperature === 'number') generationConfig.temperature = temperature;
  if (Object.keys(generationConfig).length) req.generationConfig = generationConfig;
  return req;
}

// Build SHA gets prefixed onto every cache key so each deploy automatically
// invalidates all prior AI responses. Old entries become orphaned in RTDB
// (storage cost is trivially small) and the next user past deploy regenerates.
// No manual clearCache() needed when shipping prompt/code changes.
const CACHE_VERSION = (BUILD_SHA && BUILD_SHA !== 'local') ? BUILD_SHA : 'dev';

function _sanitizeCacheKey(key) {
  if (typeof key !== 'string' || !key) {
    throw new Error('cacheKey must be a non-empty string');
  }
  // RTDB path segments cannot contain . # $ [ ] /
  const versioned = `v_${CACHE_VERSION}_${key}`;
  return versioned.replace(/[.#$[\]/]/g, '_').slice(0, 200);
}

function _cacheRef(sanitizedKey) {
  return ref(database, `aiCache/${sanitizedKey}`);
}

function _isFresh(entry, ttlMs) {
  if (!entry || typeof entry.generatedAt !== 'number') return false;
  return Date.now() - entry.generatedAt < ttlMs;
}

function _isLocked(entry) {
  if (!entry || !entry.lock) return false;
  if (typeof entry.lockedAt !== 'number') return false;
  return Date.now() - entry.lockedAt < LOCK_TTL_MS;
}

async function _readCache(sanitizedKey) {
  const snap = await get(_cacheRef(sanitizedKey));
  return snap.exists() ? snap.val() : null;
}

async function _generate(prompt, options) {
  const modelName = options.model || DEFAULT_MODEL;
  const t0 = Date.now();
  console.log('[ai.gen] →', modelName, '| input chars:', (options.system || '').length, '+', String(prompt || '').length);
  const model = await _getModel(modelName);
  const request = _buildRequest(prompt, options);
  const result = await model.generateContent(request);
  const text = result.response.text();
  console.log('[ai.gen] ←', modelName, '| output chars:', (text || '').length, '| in', Date.now() - t0, 'ms');
  return text;
}

function _isUsableCachedValue(v) {
  // Empty / whitespace-only strings are NOT usable. Earlier failures (safety
  // blocks, partial responses) could have cached "" — treat as miss so we
  // regenerate rather than render nothing forever.
  return typeof v === 'string' && v.trim().length > 0;
}

async function _runCached(prompt, options) {
  const { cacheKey, ttlMs, forceRefresh } = options;
  if (typeof ttlMs !== 'number' || ttlMs <= 0) {
    throw new Error('ttlMs (positive number) is required when cacheKey is set');
  }
  const sanitized = _sanitizeCacheKey(cacheKey);
  const cRef = _cacheRef(sanitized);
  console.log('[ai.cache] read', sanitized);

  // 1. Read existing
  let entry = await _readCache(sanitized);
  if (entry) {
    const ageMin = entry.generatedAt ? Math.round((Date.now() - entry.generatedAt) / 60000) : '?';
    const fresh = _isFresh(entry, ttlMs);
    const usable = _isUsableCachedValue(entry.value);
    const locked = _isLocked(entry);
    console.log('[ai.cache] entry exists | age(min):', ageMin, '| fresh:', fresh, '| usable:', usable, '| locked:', locked);
  } else {
    console.log('[ai.cache] no entry — fresh generation');
  }
  if (!forceRefresh && _isFresh(entry, ttlMs) && _isUsableCachedValue(entry && entry.value)) {
    console.log('[ai.cache] HIT — serving cached value');
    return entry.value;
  }

  // 2. If another tab is currently generating, wait briefly for the result.
  if (!forceRefresh && _isLocked(entry)) {
    console.log('[ai.cache] another tab locked — polling up to', POLL_MAX_MS, 'ms');
    const start = Date.now();
    while (Date.now() - start < POLL_MAX_MS) {
      await new Promise((r) => setTimeout(r, POLL_INTERVAL_MS));
      const polled = await _readCache(sanitized);
      if (
        polled &&
        _isFresh(polled, ttlMs) &&
        _isUsableCachedValue(polled.value) &&
        !polled.lock
      ) {
        console.log('[ai.cache] another tab finished — using their result');
        return polled.value;
      }
      if (!_isLocked(polled)) {
        // Lock expired without a write — fall through and generate ourselves.
        console.log('[ai.cache] lock expired — generating ourselves');
        entry = polled;
        break;
      }
    }
  }

  // 3. Set lock and generate.
  console.log('[ai.cache] MISS — acquiring lock + generating');
  try {
    await set(cRef, {
      ...(entry || {}),
      lock: true,
      lockedAt: Date.now(),
    });
  } catch (_) {
    console.log('[ai.cache] lock write failed (probably unauthenticated) — proceeding without lock');
  }

  let value;
  try {
    value = await _generate(prompt, options);
  } catch (err) {
    // Clear the lock so the next call can retry quickly. Preserve any prior
    // good value if present.
    try {
      if (entry && _isUsableCachedValue(entry.value)) {
        await set(cRef, {
          value: entry.value,
          prompt: entry.prompt || '',
          generatedAt: entry.generatedAt || Date.now(),
          ttlMs: entry.ttlMs || ttlMs,
        });
      } else {
        await remove(cRef);
      }
    } catch (_) {}
    if (typeof console !== 'undefined' && console.warn) {
      console.warn('[ai.runPrompt] generateContent failed:', err && (err.message || err));
    }
    throw err;
  }

  // Empty result (safety block, model returned nothing) — do NOT cache it.
  if (!_isUsableCachedValue(value)) {
    try {
      if (entry && _isUsableCachedValue(entry.value)) {
        await set(cRef, {
          value: entry.value,
          prompt: entry.prompt || '',
          generatedAt: entry.generatedAt || Date.now(),
          ttlMs: entry.ttlMs || ttlMs,
        });
      } else {
        await remove(cRef);
      }
    } catch (_) {}
    if (typeof console !== 'undefined' && console.warn) {
      console.warn('[ai.runPrompt] empty response — not caching. cacheKey=', sanitized);
    }
    return value;
  }

  // 4. Persist result.
  console.log('[ai.cache] write', sanitized, '| value chars:', (value || '').length);
  await set(cRef, {
    value,
    prompt: typeof prompt === 'string' ? prompt.slice(0, 2000) : '',
    generatedAt: serverTimestamp(),
    ttlMs,
  });

  return value;
}

export async function runPrompt(prompt, options = {}) {
  if (options.cacheKey) {
    return _runCached(prompt, options);
  }
  return _generate(prompt, options);
}

export async function streamPrompt(prompt, onChunk, options = {}) {
  const model = await _getModel(options.model || DEFAULT_MODEL);
  const request = _buildRequest(prompt, options);
  const result = await model.generateContentStream(request);
  let full = '';
  for await (const chunk of result.stream) {
    const piece = chunk.text();
    full += piece;
    if (typeof onChunk === 'function') onChunk(piece);
  }
  return full;
}

export async function getCachedPrompt(cacheKey) {
  if (!cacheKey) return null;
  const sanitized = _sanitizeCacheKey(cacheKey);
  const entry = await _readCache(sanitized);
  if (entry && _isUsableCachedValue(entry.value)) return entry.value;
  return null;
}

export function sanitizeCacheKey(cacheKey) {
  return _sanitizeCacheKey(cacheKey);
}

export async function _readCacheRaw(cacheKey) {
  // Diagnostic helper: returns the raw RTDB entry (lock, generatedAt, value, etc.)
  if (!cacheKey) return null;
  const sanitized = _sanitizeCacheKey(cacheKey);
  return _readCache(sanitized);
}

export async function clearCache(cacheKey) {
  if (cacheKey) {
    const sanitized = _sanitizeCacheKey(cacheKey);
    await remove(_cacheRef(sanitized));
    return;
  }
  await remove(ref(database, 'aiCache'));
}

// Exposed in production too — the AI calls are auth-bound via Firebase App
// config (apiKey is public anyway), and console access lets admins debug.
if (typeof window !== 'undefined') {
  window.__sl_ai = {
    runPrompt,
    streamPrompt,
    getCachedPrompt,
    clearCache,
    _readCacheRaw,
    _sanitizeCacheKey,
  };
}

export { app };
